odule.namespace;\r\n        navigate(path);\r\n        selectModule(module);\r\n    };\r\n    let selectApplication = () => {\r\n        if (selectedApplication) selectedApplication = null;\r\n        else {\r\n            selectedApplication = application.namespace;\r\n        }\r\n    };\r\n\r\n    moduleStore.subscribe((s) => {\r\n        if (application && s && s.selectedModule) {\r\n            if (s.selectedModule.indexOf(application.namespace) === 0) {\r\n                selectedApplication = application.namespace;\r\n            }\r\n        }\r\n    });\r\n</script>\r\n\r\n{#if application}\r\n    <div class=\"application\">\r\n        <title on:click={selectApplication}\r\n            ><i class=\"fa fa-institution\" />{application.name}</title>\r\n        {#if selectedApplication === application.namespace}\r\n            <div class=\"application--details\">\r\n                {#if components.length > 0}\r\n                    <h2>Components</h2>\r\n                    {#each components as node}\r\n                        <div\r\n                            class=\"item item--node\"\r\n                            class:selected={node.namespace ==\r\n                                $moduleStore.selectedModule}\r\n                            on:click={onClick(node)}>\r\n                            <i class=\"fa fa-cogs\" />{node.name}\r\n                        </div>\r\n                    {/each}\r\n                {/if}\r\n\r\n                {#if endpoints.length > 0}\r\n                    <h2>Endpoints</h2>\r\n                    {#each endpoints as node}\r\n                        <div\r\n                            class=\"item item--node\"\r\n                            class:selected={node.namespace ==\r\n                                $moduleStore.selectedModule}\r\n                            on:click={onClick(node)}>\r\n                            <i class=\"fa fa-envelope\" />{node.name}\r\n                        </div>\r\n                    {/each}\r\n                {/if}\r\n\r\n                {#if features.length > 0}\r\n                    <h2>Features</h2>\r\n                    {#each features as node}\r\n                        <div\r\n                            class=\"item item--node\"\r\n                            class:selected={node.namespace ==\r\n                                $moduleStore.selectedModule}\r\n                            on:click={onClick(node)}>\r\n                            <i class=\"fa fa-diamond\" />{node.name}\r\n                        </div>\r\n                    {/each}\r\n                {/if}\r\n\r\n                {#if databases.length > 0}\r\n                    <h2>Databases</h2>\r\n                    {#each databases as node}\r\n                        <div\r\n                            class=\"item item--node\"\r\n                            class:selected={node.namespace ==\r\n                                $moduleStore.selectedModule}\r\n                            on:click={onClick(node)}>\r\n                            <i class=\"fa fa-database\" />{node.name}\r\n                        </div>\r\n                    {/each}\r\n                {/if}\r\n            </div>\r\n        {/if}\r\n    </div>\r\n{/if}\r\n\r\n<style type=\"less\">\r\n    .application {\r\n        display: block;\r\n        padding: 0;\r\n        margin: 0;\r\n        border-bottom: 1px solid var(--color-1--bg);\r\n        font-size: 12px;\r\n\r\n        user-select: none;\r\n\r\n        & * {\r\n            user-select: none;\r\n        }\r\n\r\n        .application--details {\r\n            padding-left: 1rem;\r\n        }\r\n\r\n        title {\r\n            padding: 0;\r\n            margin: 0;\r\n            background: var(--color-1--border);\r\n            padding: 0.5rem;\r\n            display: block;\r\n            width: 100%;\r\n\r\n            i {\r\n                display: inline-block;\r\n                margin-right: 0.5rem;\r\n            }\r\n        }\r\n\r\n        h2 {\r\n            margin: 0;\r\n            padding: 0;\r\n            font-size: 0.6rem;\r\n            text-transform: uppercase;\r\n            margin-top: 10px;\r\n        }\r\n\r\n        .item {\r\n            margin-left: -1rem;\r\n            padding: 0.5rem 0.5rem 0.5rem 1.5rem;\r\n            &:hover {\r\n                cursor: pointer;\r\n                color: var(--color-3);\r\n            }\r\n            .fa {\r\n                display: inline-block;\r\n                margin-right: 0.5rem;\r\n            }\r\n\r\n            &.selected {\r\n                background: var(--color-3);\r\n                color: var(--color-3--text);\r\n            }\r\n        }\r\n    }\r\n</style>\r\n","<script>\r\n    import Domain from \"./Domain.svelte\";\r\n    import FileToolbar from \"./FileToolbar.svelte\";\r\n    import { stateStore } from \"./../../Services/state\";\r\n    import Application from \"./Application.svelte\";\r\n\r\n    // getFiles();\r\n\r\n    var applications = [];\r\n    var selectedApplication = null;\r\n    stateStore.subscribe(({ files = {} }) => {\r\n        applications = [];\r\n        setTimeout(() => {\r\n            applications = files.applications || [];\r\n        });\r\n    });\r\n</script>\r\n\r\n<div class=\"file-explorer\">\r\n    {#each applications as application}\r\n        <Application {application} bind:selectedApplication />\r\n    {/each}\r\n</div>\r\n\r\n<style>\r\n    .file-explorer {\r\n        height: 100%;\r\n        border-right: 1px solid var(--color-1--border);\r\n        background-color: var(--color-1--bg);\r\n        overflow: hidden;\r\n        padding-top: 2rem;\r\n    }\r\n</style>\r\n","<script>\r\n    import { createEventDispatcher } from \"svelte\";\r\n    import { onMount, onDestroy, afterUpdate } from \"svelte\";\r\n    import { writable } from \"svelte/store\";\r\n    // import { selectWord } from \"../Services/selection\";\r\n\r\n    const dispatch = createEventDispatcher();\r\n\r\n    export let onKeyPress = () => {};\r\n    let id = \"editor-\" + Math.floor(Math.random() * 1000);\r\n    let editor = null;\r\n    export let text = \"\";\r\n    export let language = \"carlang\";\r\n    export let theme = \"carlangTheme\";\r\n    export let wordWrap = true;\r\n    export let markers = writable([]);\r\n    export let context = [];\r\n\r\n    let f = context;\r\n\r\n    let editorContainer;\r\n\r\n    if (markers) {\r\n        markers.subscribe((m) => {\r\n            if (!editor) return;\r\n            var model = editor.getModel();\r\n            monaco.editor.setModelMarkers(model, \"\", m);\r\n        });\r\n    }\r\n    let timeout;\r\n    const initEditor = () => {\r\n        editor = monaco.editor.create(document.getElementById(id), {\r\n            value: text || \"\",\r\n            language: language,\r\n            theme: theme,\r\n            scrollBeyondLastLine: true,\r\n            roundedSelection: true,\r\n            fontSize: \"16px\",\r\n            wordWrapColumn: 120,\r\n            wordWrap: wordWrap ? \"on\" : \"off\",\r\n            minimap: {\r\n                enabled: false,\r\n            },\r\n            quickSuggestions: {\r\n                other: false,\r\n                comments: false,\r\n                strings: false,\r\n            },\r\n        });\r\n        editor.dragAndDrop = false;\r\n        window.addEventListener(\"keydown\", keyTrap, true);\r\n        editor.onMouseDown(function (e) {\r\n            if (e.event.ctrlKey && e.event.leftButton) {\r\n                var word = editor\r\n                    .getModel()\r\n                    .getWordAtPosition(e.target.position);\r\n                onKeyPress(word);\r\n            }\r\n        });\r\n        editor.onDidChangeModelContent(function (e) {\r\n            if (timeout) clearTimeout(timeout);\r\n            timeout = setTimeout(() => {\r\n                dispatch(\"change\", editor.getValue());\r\n            }, 200);\r\n        });\r\n\r\n        // monaco.languages.registerCompletionItemProvider(\"carlang\", {\r\n        //     //TODO: implement completion provider\r\n        //     // triggerCharacters: [\"\"],\r\n        //     // provideCompletionItems: function (model, position) {\r\n        //     //     let suggestions = [\r\n        //     //         {\r\n        //     //             label: \"component\",\r\n        //     //             kind: monaco.languages.CompletionItemKind.Keyword,\r\n        //     //             documentation: \"Initialize a component\",\r\n        //     //             insertText: \"component\",\r\n        //     //         },\r\n        //     //     ];\r\n        //     //     var foo = context;\r\n        //     //     console.log(suggestions);\r\n        //     //     return suggestions;\r\n        //     // },\r\n        // });\r\n    };\r\n    onMount(() => {\r\n        initEditor();\r\n        var ro = new ResizeObserver(() => {\r\n            editor.layout();\r\n        });\r\n        ro.observe(editorContainer);\r\n    });\r\n    onDestroy(() => {\r\n        window.removeEventListener(\"keydown\", keyTrap, true);\r\n    });\r\n\r\n    $: if (language) {\r\n        (() => {\r\n            if (!editor) return;\r\n            monaco.editor.setModelLanguage(editor.getModel(), language);\r\n        })();\r\n    }\r\n\r\n    $: if (text || text === \"\") {\r\n        (() => {\r\n            if (!editor) return;\r\n\r\n            const model = editor.getModel();\r\n            const position = editor.getPosition();\r\n            if (text != null && text !== model.getValue()) {\r\n                editor.pushUndoStop();\r\n                model.pushEditOperations(\r\n                    [],\r\n                    [\r\n                        {\r\n                            range: model.getFullModelRange(),\r\n                            text: text,\r\n                        },\r\n                    ]\r\n                );\r\n                editor.pushUndoStop();\r\n                editor.setPosition(position);\r\n            }\r\n        })();\r\n    }\r\n\r\n    function keyTrap(e) {\r\n        if (editor.hasTextFocus()) {\r\n            if ((e.ctrlKey === true || e.metaKey == true) && e.key == \"s\") {\r\n                dispatch(\"save\", editor.getValue());\r\n                onKeyPress(e, editor.getValue());\r\n                e.preventDefault();\r\n                return false;\r\n            } else if (language === \"carlang\" && e.key == \"F2\") {\r\n                var wordUnderCursor = editor\r\n                    .getModel()\r\n                    .getWordAtPosition(editor.getPosition());\r\n                if (wordUnderCursor && wordUnderCursor.word) {\r\n                    // console.log(wordUnderCursor.word);\r\n                    console.log(wordUnderCursor.word);\r\n                }\r\n            } else {\r\n                // console.log(e);\r\n            }\r\n        }\r\n    }\r\n</script>\r\n\r\n<div class=\"editor\" {id} bind:this={editorContainer} />\r\n\r\n<style>\r\n    .editor {\r\n        height: 100%;\r\n        width: 100%;\r\n    }\r\n</style>\r\n","<script type=\"ts\">\r\n    import { writable } from \"svelte/store\";\r\n    import Editor from \"./Editor.svelte\";\r\n    import { moduleStore, parseCode, selectModule } from \"../Services/module\";\r\n\r\n    export let context = [];\r\n\r\n    let module;\r\n    let text = \"\";\r\n    let type = \"carlang\";\r\n    let markers = writable([]);\r\n\r\n    let onSave = async (event) => {\r\n        if (!module || !event) return;\r\n        let code = event.detail;\r\n        parseCode(module, code);\r\n    };\r\n\r\n    let mapErrorToken = (e) => {\r\n        return {\r\n            startLineNumber: e.sourceSegment.lineStart + 1,\r\n            endLineNumber: e.sourceSegment.lineEnd + 1,\r\n            startColumn: e.sourceSegment.columnStart + 1,\r\n            endColumn: e.sourceSegment.columnEnd + 1,\r\n            message: e.message,\r\n        };\r\n    };\r\n\r\n    moduleStore.subscribe((value: any) => {\r\n        if (!value || !value.modules || !value.selectedModule) return;\r\n\r\n        module = value.modules[value.selectedModule];\r\n        if (!module) {\r\n            text = \"\";\r\n            markers.set([]);\r\n            return;\r\n        }\r\n        text = module.text;\r\n        var errors = module.compilationResult?.errors || [];\r\n        var mappedErrors = errors.map(mapErrorToken);\r\n        markers.set(mappedErrors);\r\n\r\n        if (module && module.path && module.path.endsWith(\".json\")) {\r\n            type = \"json\";\r\n            text = JSON.stringify(JSON.parse(text), null, 4);\r\n        } else {\r\n            type = \"carlang\";\r\n        }\r\n    });\r\n</script>\r\n\r\n<div class=\"container\">\r\n    <div class=\"header\">\r\n        {module ? module.namespace || module.path : \"unknown file\"}\r\n    </div>\r\n\r\n    <div class=\"editor\">\r\n        <Editor {context} {text} {markers} language={type} on:save={onSave} />\r\n    </div>\r\n</div>\r\n\r\n<style type=\"less\">\r\n    .container {\r\n        height: 100%;\r\n        width: 100%;\r\n        display: grid;\r\n        grid-template-rows: min-content auto min-content;\r\n        grid-gap: 0;\r\n\r\n        .header,\r\n        .footer {\r\n            // padding: 0.5rem;\r\n            color: var(--color-1--font);\r\n            background: var(--color-1);\r\n            // border-right: 1px solid var(--color-1--border);\r\n            height: 2rem;\r\n            line-height: 2rem;\r\n            padding-left: 1rem;\r\n            font-size: 0.8rem;\r\n        }\r\n        .header {\r\n            grid-row: 1;\r\n            border-bottom: 1px solid var(--color-1--border);\r\n        }\r\n        .footer {\r\n            grid-row: 3;\r\n            border-top: 1px solid var(--color-1--border);\r\n        }\r\n        .editor {\r\n            grid-row: 2;\r\n            // border-right: 1px solid var(--color-1--border);\r\n        }\r\n\r\n        .sep {\r\n            box-shadow: black 0 6px 6px -6px inset;\r\n        }\r\n    }\r\n</style>\r\n","<script type=\"ts\">\r\n    import {\r\n        Tabs,\r\n        TabList,\r\n        TabPanel,\r\n        Tab,\r\n        Modal,\r\n    } from \"../Components/components.js\";\r\n    import PageViewer from \"../Components/PageViewer.svelte\";\r\n    import FileExplorer from \"../Components/FileExplorer/FileExplorer.svelte\";\r\n    import DocumentEditor from \"../Components/DocumentEditor.svelte\";\r\n    import Panel from \"../Components/Panel.svelte\";\r\n    import {\r\n        moduleStore,\r\n        selectModuleByNamespace,\r\n    } from \"../Services/module.js\";\r\n    import { onMount, onDestroy } from \"svelte\";\r\n\r\n    export let namespace = \"\";\r\n    var oldNamespace = \"\";\r\n\r\n    let iframe;\r\n    let timeout;\r\n    let module;\r\n    let svgUrl;\r\n    let componentUrl;\r\n    let planningSvgUrl;\r\n    let htmlUrl;\r\n    let scrollY = 0;\r\n\r\n    let context = [];\r\n\r\n    const generateUrls = (event) => {\r\n        scrollY = iframe?.contentWindow.scrollY ?? 0;\r\n\r\n        if (!namespace) return;\r\n        svgUrl = `/documents/${namespace}/data.svg?timestamp=${new Date().getMilliseconds()}`;\r\n        componentUrl = `/documents/${namespace}/components.svg?timestamp=${new Date().getMilliseconds()}`;\r\n        planningSvgUrl = `/documents/${namespace}/roadmap.svg?timestamp=${new Date().getMilliseconds()}`;\r\n        htmlUrl = `/documents/${namespace}/page.html?timestamp=${new Date().getMilliseconds()}`;\r\n    };\r\n\r\n    onMount(() => {\r\n        window.addEventListener(\"module_changed\", generateUrls, false);\r\n        generateUrls({});\r\n    });\r\n    onDestroy(() => {\r\n        window.removeEventListener(\"module_changed\", generateUrls, false);\r\n    });\r\n\r\n    let print = () => {\r\n        iframe.contentWindow.focus();\r\n        iframe.contentWindow.print();\r\n    };\r\n\r\n    $: {\r\n        if (moduleStore && oldNamespace !== namespace) {\r\n            selectModuleByNamespace(namespace);\r\n            generateUrls(namespace);\r\n            oldNamespace = namespace;\r\n        }\r\n        if (iframe && !iframe.onload) {\r\n            iframe.onload = function () {\r\n                setTimeout(() => {\r\n                    iframe?.contentWindow.scroll(0, scrollY);\r\n                });\r\n            };\r\n        }\r\n    }\r\n</script>\r\n\r\n<div class=\"container\">\r\n    <div class=\"file-explorer--container\">\r\n        <FileExplorer />\r\n    </div>\r\n    <div class=\"document-editor\">\r\n        <div>\r\n            <DocumentEditor {context} />\r\n        </div>\r\n    </div>\r\n    <div class=\"page-viewer\">\r\n        <Tabs>\r\n            <TabList>\r\n                <Tab>Document</Tab>\r\n                <Tab>Architecture</Tab>\r\n                <Tab>Data Model</Tab>\r\n                <Tab>Planning</Tab>\r\n            </TabList>\r\n\r\n            <TabPanel>\r\n                {#if htmlUrl}\r\n                    <Panel\r\n                        style=\"background:var(--color-1); overflow:hidden!important; height: calc(100% - 3rem); margin-top: 2.5rem; padding: 2rem 0 2rem 0;\">\r\n                        <PageViewer>\r\n                            <!-- <PageViewer url={htmlUrl} /> -->\r\n                            <iframe\r\n                                bind:this={iframe}\r\n                                class=\"html-iframe\"\r\n                                src={htmlUrl}\r\n                                title=\"Page\" />\r\n                        </PageViewer>\r\n                    </Panel>\r\n                {/if}\r\n            </TabPanel>\r\n\r\n            <TabPanel>\r\n                <Panel style=\"height: calc(100% - 3rem); overflow:auto;\">\r\n                    {#if svgUrl}\r\n                        <img alt=\"svg\" src={componentUrl} />\r\n                    {/if}\r\n                </Panel>\r\n            </TabPanel>\r\n\r\n            <TabPanel>\r\n                <Panel style=\"height: calc(100% - 3rem); overflow:auto;\">\r\n                    {#if svgUrl}\r\n                        <img alt=\"svg\" src={svgUrl} />\r\n                    {/if}\r\n                </Panel>\r\n            </TabPanel>\r\n\r\n            <TabPanel>\r\n                <Panel style=\"height: calc(100% - 3rem); overflow:auto;\">\r\n                    {#if planningSvgUrl}\r\n                        <img\r\n                            style=\"min-width:100%; max-width:100%;\"\r\n                            alt=\"svg\"\r\n                            src={planningSvgUrl} />\r\n                    {/if}\r\n                </Panel>\r\n            </TabPanel>\r\n        </Tabs>\r\n\r\n        <div class=\"print-button\" on:click={print}>\r\n            <i class=\"fa fa-print\" />\r\n        </div>\r\n    </div>\r\n</div>\r\n\r\n<style type=\"less\">\r\n    .container {\r\n        height: 100%;\r\n        width: 100%;\r\n        display: grid;\r\n        grid-template-columns: 300px 750px auto;\r\n        grid-gap: 1px;\r\n\r\n        .file-explorer--container {\r\n            grid-column: 1;\r\n            height: 100%;\r\n            max-height: 100%;\r\n            overflow: auto;\r\n            background: white;\r\n        }\r\n        .document-editor {\r\n            grid-column: 2;\r\n            height: 100%;\r\n            max-height: 100%;\r\n            div {\r\n                width: 100%;\r\n                height: 100%;\r\n            }\r\n        }\r\n        .page-viewer {\r\n            position: relative;\r\n            grid-column: 3;\r\n            font-family: sans-serif;\r\n            padding: 0;\r\n            margin: 0;\r\n            height: 100%;\r\n            max-height: 100%;\r\n            overflow-x: hidden;\r\n            overflow-y: hidden;\r\n            background-color: white;\r\n        }\r\n    }\r\n    img {\r\n        max-width: 100%;\r\n        max-height: 100%;\r\n    }\r\n    i {\r\n        display: block;\r\n        &:hover {\r\n            color: pink;\r\n            cursor: pointer;\r\n        }\r\n    }\r\n    .html-iframe {\r\n        min-width: 21cm;\r\n        max-width: 21cm;\r\n        width: 21cm;\r\n\r\n        border: none;\r\n        height: 100%;\r\n\r\n        background: white;\r\n\r\n        margin-left: 2rem;\r\n    }\r\n    .print-button {\r\n        position: fixed;\r\n        z-index: 99999;\r\n        right: 1rem;\r\n        bottom: 0rem;\r\n        height: 32px;\r\n        width: 32px;\r\n    }\r\n</style>\r\n","<script>\r\n    import { post } from \"./../Services/http\";\r\n    import { stateStore, selectApplication } from \"./../Services/state\";\r\n\r\n    let applications = [];\r\n    let selectedApp;\r\n\r\n    var a = localStorage.getItem(\"applications\");\r\n    if (a != null) {\r\n        applications = JSON.parse(a).sort();\r\n    }\r\n\r\n    let sa = async (app) => {\r\n        selectApplication(app);\r\n        let pUrl = app.replace(/\\//g, \"__$__\").replace(/\\\\/g, \"__$__\");\r\n        await post(\"/project/init/\" + pUrl, {});\r\n    };\r\n\r\n    stateStore.subscribe((s) => {\r\n        selectedApp = s.application;\r\n    });\r\n</script>\r\n\r\n<div class=\"home\">\r\n    {#each applications as application}\r\n        <div\r\n            class=\"application\"\r\n            class:selected={selectedApp == application}\r\n            on:click={() => sa(application)}>\r\n            {#if selectedApp == application}\r\n                <i class=\"fa fa-check\" />\r\n            {/if}\r\n            <span>{application}</span>\r\n        </div>\r\n    {/each}\r\n</div>\r\n\r\n<style type=\"less\">\r\n    .home {\r\n        padding: 1rem;\r\n        display: flex;\r\n        flex-wrap: wrap;\r\n\r\n        .application {\r\n            margin: 0.5rem;\r\n            display: block;\r\n            height: 10rem;\r\n            width: 10rem;\r\n            background-color: var(--color-1--border);\r\n            color: var(--color-1--font);\r\n            position: relative;\r\n            font-size: 10px;\r\n\r\n            i {\r\n                position: absolute;\r\n                top: 1rem;\r\n                right: 1rem;\r\n            }\r\n\r\n            &.selected {\r\n                background-color: var(--color-3);\r\n            }\r\n\r\n            &:hover {\r\n                cursor: pointer;\r\n            }\r\n\r\n            span {\r\n                position: absolute;\r\n                left: 50%;\r\n                top: 50%;\r\n                transform: translate(-50%, -50%);\r\n                user-select: none;\r\n            }\r\n        }\r\n    }\r\n</style>\r\n","<script>\r\n    import { navigate } from \"svelte-routing\";\r\n    export let href = undefined;\r\n    export let title = \"\";\r\n    export let onClick = () => {};\r\n    export let selected = false;\r\n    export let icon = undefined;\r\n    export let restricted = false;\r\n    export let link = false;\r\n\r\n    const click = () => {\r\n        if (onClick) onClick();\r\n        if (href && !restricted) navigate(href);\r\n    };\r\n</script>\r\n\r\n<style type=\"less\">\r\n    .nav-button {\r\n        display: inline-block;\r\n        text-align: center;\r\n        &:hover {\r\n            cursor: pointer;\r\n        }\r\n    }\r\n    .link {\r\n        text-decoration: underline;\r\n    }\r\n    .link:hover {\r\n        cursor: pointer;\r\n    }\r\n    .nav-button.icon i {\r\n        font-size: 2rem;\r\n        margin-bottom: 0.5rem;\r\n    }\r\n</style>\r\n\r\n{#if icon}\r\n    <span class=\"nav-button icon\" class:selected class:link on:click={click}>\r\n        <i class={icon} />\r\n        <br />\r\n        {#if title && title.length > 0}<span class=\"title\">{title}</span>{/if}\r\n    </span>\r\n{:else}\r\n    <span class=\"nav-button\" class:selected class:link on:click={click}>\r\n        {title}\r\n    </span>\r\n{/if}\r\n","<script>\r\n    import { Link } from \"svelte-routing\";\r\n    import NavButton from \"./NavButton.svelte\";\r\n    import { stateStore } from \"./../Services/state\";\r\n\r\n    let selectedApp;\r\n    stateStore.subscribe((s) => {\r\n        selectedApp = s.application;\r\n    });\r\n</script>\r\n\r\n<nav>\r\n    <NavButton href=\"/\" icon=\"fa fa-home\" title=\"Home\" />\r\n    {#if selectedApp}\r\n        <NavButton href=\"editor\" icon=\"fa fa-file\" title=\"Editor\" />\r\n    {/if}\r\n</nav>\r\n\r\n<style type=\"less\">\r\n    nav {\r\n        flex: 0;\r\n        height: 100%;\r\n\r\n        background: var(--color-1);\r\n        color: var(--color-1--alt);\r\n        padding: 1rem;\r\n        padding-top: 2rem;\r\n\r\n        text-align: center;\r\n\r\n        display: grid;\r\n        grid-auto-rows: 75px;\r\n        row-gap: 1rem;\r\n    }\r\n</style>\r\n","<script>\r\n    import { writable } from \"svelte/store\";\r\n    import Application from \"../Components/FileExplorer/Application.svelte\";\r\n    import { post } from \"../Services/http\";\r\n\r\n    export let close;\r\n\r\n    var app = writable();\r\n    const changeValue = (name) => (e) => {\r\n        $app = { ...$app, [name]: e.target.value };\r\n    };\r\n\r\n    const submitForm = async () => {\r\n        try {\r\n            let validateApp = ({ path }) => {\r\n                return path;\r\n            };\r\n\r\n            let isValid = validateApp($app);\r\n            let path = $app.path;\r\n            if (isValid) {\r\n                var applications = localStorage.getItem(\"applications\");\r\n                if (applications == null) applications = [];\r\n                else applications = JSON.parse(applications);\r\n                if (applications.indexOf(path) < 0) {\r\n                    applications.unshift(path);\r\n                    localStorage.setItem(\r\n                        \"applications\",\r\n                        JSON.stringify(applications)\r\n                    );\r\n                }\r\n\r\n                let pUrl = path.replace(/\\//g, \"__$__\").replace(/\\\\/g, \"__$__\");\r\n                await post(\"/project/init/\" + pUrl, {});\r\n                close();\r\n            }\r\n        } catch (err) {\r\n            console.log(err);\r\n        }\r\n    };\r\n</script>\r\n\r\n<form class=\"form\">\r\n    <div class=\"note\">\r\n        Because of the limitations of the web we cannot select a directory from\r\n        the file system. This is why we will need a full path to open the\r\n        correct directory.\r\n    </div>\r\n    <div class=\"form--field\">\r\n        <label for=\"ca_001\">Folder Full Path</label>\r\n        <input id=\"ca_001\" on:change={changeValue(\"path\")} />\r\n    </div>\r\n\r\n    <button on:click={submitForm} type=\"button\">Submit</button>\r\n</form>\r\n\r\n<style>\r\n    .note {\r\n        margin-bottom: 1rem;\r\n    }\r\n</style>\r\n","<script>\r\n    import { writable } from \"svelte/store\";\r\n    import { post } from \"../Services/http\";\r\n    import { toggleAddFileDialog } from \"../Services/state\";\r\n\r\n    var file = writable({\r\n        type: \"Feature\",\r\n    });\r\n    const changeValue = (name) => (e) => {\r\n        $file = { ...$file, [name]: e.target.value };\r\n    };\r\n\r\n    const submitForm = async () => {\r\n        try {\r\n            let validateFile = ({ name, type, appName, description }) => {\r\n                return name && type;\r\n            };\r\n            let isValid = validateFile($file);\r\n            if (isValid) {\r\n                await post(\"/file/.\", $file);\r\n                toggleAddFileDialog();\r\n            }\r\n        } catch (err) {\r\n            console.log(err);\r\n        }\r\n    };\r\n</script>\r\n\r\n<form class=\"form\">\r\n    <div class=\"form--field\">\r\n        <label for=\"cf_001\">File Name</label>\r\n        <input id=\"cf_001\" on:change={changeValue(\"name\")} />\r\n    </div>\r\n\r\n    <div class=\"form--field\">\r\n        <label for=\"cf_002\">Type</label>\r\n        <select id=\"cf_002\" value={$file.type} on:change={changeValue(\"type\")}>\r\n            <option />\r\n            <option>Component</option>\r\n            <option>Feature</option>\r\n            <option>Database</option>\r\n            <option>Endpoint</option>\r\n            <option>Model</option>\r\n            <option>Empty</option>\r\n        </select>\r\n    </div>\r\n\r\n    <div class=\"form--field\">\r\n        <label for=\"cf_003\">Application Name</label>\r\n        <input id=\"cf_003\" on:change={changeValue(\"appName\")} />\r\n    </div>\r\n\r\n    <div class=\"form--field\">\r\n        <label for=\"cf_004\">Description</label>\r\n        <textarea id=\"cf_004\" on:change={changeValue(\"description\")} />\r\n    </div>\r\n\r\n    <button on:click={submitForm} type=\"button\">Submit</button>\r\n</form>\r\n","<script>\r\n    import { writable } from \"svelte/store\";\r\n    import { post } from \"../Services/http\";\r\n    import { toggleAddApplicationDialog } from \"../Services/state\";\r\n\r\n    var app = writable();\r\n    const changeValue = (name) => (e) => {\r\n        $app = { ...$app, [name]: e.target.value };\r\n    };\r\n\r\n    const submitForm = async () => {\r\n        try {\r\n            let validateApp = ({ name }) => {\r\n                return name;\r\n            };\r\n            let isValid = validateApp($app);\r\n            if (isValid) {\r\n                await post(\"/application\", $app);\r\n                toggleAddApplicationDialog();\r\n            }\r\n        } catch (err) {\r\n            console.log(err);\r\n        }\r\n    };\r\n</script>\r\n\r\n<form class=\"form\">\r\n    <div class=\"form--field\">\r\n        <label for=\"ca_001\">Application Name</label>\r\n        <input id=\"ca_001\" on:change={changeValue(\"name\")} />\r\n    </div>\r\n\r\n    <button on:click={submitForm} type=\"button\">Submit</button>\r\n</form>\r\n","<script>\r\n    export let icon;\r\n    export let title;\r\n\r\n    import { createEventDispatcher } from \"svelte\";\r\n    const dispatch = createEventDispatcher();\r\n\r\n    const clicked = () => {\r\n        dispatch(\"click\", title);\r\n    };\r\n</script>\r\n\r\n<div class=\"app--toole-bar--item\" on:click={clicked}>\r\n    <div class=\"inner\">\r\n        <i class={icon} />\r\n        <span>{title}</span>\r\n    </div>\r\n</div>\r\n\r\n<style type=\"less\">\r\n    .app--toole-bar--item {\r\n        margin: 0;\r\n        padding: 0;\r\n        width: 10rem;\r\n        border-left: 1px solid var(--color-1--border);\r\n        border-right: 1px solid var(--color-1--border);\r\n        height: 100%;\r\n        position: relative;\r\n        user-select: none;\r\n\r\n        &:hover {\r\n            cursor: pointer;\r\n            background-color: var(--color-2);\r\n        }\r\n\r\n        .inner {\r\n            position: absolute;\r\n            left: 50%;\r\n            top: 50%;\r\n            transform: translate(-50%, -50%);\r\n            display: flex;\r\n            flex-direction: row;\r\n            align-items: center;\r\n            justify-content: center;\r\n            i {\r\n                display: inline-block;\r\n                margin-right: 0.5rem;\r\n                margin-top: 1px;\r\n            }\r\n            span {\r\n                white-space: nowrap;\r\n            }\r\n        }\r\n    }\r\n</style>\r\n","<script>\r\n    import SelectFolder from \"../../Forms/SelectFolder.svelte\";\r\n    import {\r\n        toggleAddApplicationDialog,\r\n        toggleAddFileDialog,\r\n        toggleRefactorDialog,\r\n    } from \"../../Services/state\";\r\n\r\n    import CreateFile from \"../../Forms/CreateFile.svelte\";\r\n    import CreateApplication from \"../../Forms/CreateApplication.svelte\";\r\n    import Modal from \"../Modal.svelte\";\r\n    import ToolbarItem from \"./ToolbarItem.svelte\";\r\n    import { stateStore } from \"./../../Services/state\";\r\n\r\n    let show = false;\r\n    let selectDirectory = () => {\r\n        show = !show;\r\n    };\r\n\r\n    let selectedApp;\r\n    stateStore.subscribe((s) => {\r\n        selectedApp = s.application;\r\n    });\r\n\r\n    let showAddApplicationDialog = false;\r\n    let showAddFileDialog = false;\r\n    let showRefactorDialog = false;\r\n\r\n    stateStore.subscribe((s) => {\r\n        showAddFileDialog = !!s.showAddFileDialog;\r\n        showAddApplicationDialog = !!s.showAddApplicationDialog;\r\n        showRefactorDialog = !!s.showRefactorDialog;\r\n    });\r\n</script>\r\n\r\n<div class=\"app--toolbar\">\r\n    <div class=\"filler\">\r\n        <img style=\"height:1.5rem;\" src=\"favicon.ico\" alt=\"fav\" />\r\n        ZDragon\r\n    </div>\r\n    {#if selectedApp}\r\n        <ToolbarItem\r\n            icon=\"fa fa-plus\"\r\n            title=\"New App\"\r\n            on:click={toggleAddApplicationDialog} />\r\n        <ToolbarItem\r\n            icon=\"fa fa-plus\"\r\n            title=\"New File\"\r\n            on:click={toggleAddFileDialog} />\r\n    {/if}\r\n    <ToolbarItem icon=\"fa fa-folder\" title=\"Open\" on:click={selectDirectory} />\r\n    <!-- <ToolbarItem icon=\"fa fa-floppy-o\" title=\"Save\" /> -->\r\n\r\n    <div class=\"app--toolbar--close\">\r\n        <i class=\"fa fa-times\" />\r\n    </div>\r\n</div>\r\n\r\n<Modal title=\"Select Directory\" {show} close={() => (show = false)}>\r\n    <SelectFolder close={() => (show = false)} />\r\n</Modal>\r\n<Modal title=\"Add File\" show={showAddFileDialog} close={toggleAddFileDialog}>\r\n    <CreateFile />\r\n</Modal>\r\n<Modal\r\n    title=\"Add Application\"\r\n    show={showAddApplicationDialog}\r\n    close={toggleAddApplicationDialog}>\r\n    <CreateApplication />\r\n</Modal>\r\n\r\n<style type=\"less\">\r\n    .filler {\r\n        height: 3rem;\r\n        line-height: 3rem;\r\n        padding: 0 1rem 0 3rem;\r\n        position: relative;\r\n        img {\r\n            position: absolute;\r\n            left: 1rem;\r\n            top: 50%;\r\n            transform: translateY(-50%);\r\n        }\r\n    }\r\n    .app--toolbar {\r\n        font-size: 0.8rem;\r\n        margin: 0;\r\n        padding: 0;\r\n        width: 100%;\r\n        height: 3rem;\r\n        background-color: var(--color-1--bg);\r\n        border-bottom: 1px solid var(--color-1--border);\r\n        flex: 0;\r\n        display: flex;\r\n        flex-direction: row;\r\n\r\n        align-items: flex-start;\r\n        justify-content: flex-start;\r\n\r\n        -webkit-app-region: drag !important;\r\n\r\n        &--close {\r\n            display: inline-block;\r\n            position: absolute;\r\n            right: 1rem;\r\n            color: var(--color-1--font);\r\n            height: 1rem;\r\n            width: 1rem;\r\n            // background: maroon;\r\n            top: 1rem;\r\n\r\n            &:hover {\r\n                cursor: pointer;\r\n            }\r\n        }\r\n    }\r\n</style>\r\n","<script>\r\n  import { Router, Route } from \"svelte-routing\";\r\n\r\n  import EditorPage from \"./Pages/EditorPage.svelte\";\r\n  import Home from \"./Pages/Home.svelte\";\r\n  import About from \"./Pages/About.svelte\";\r\n  import Menu from \"./Components/Menu.svelte\";\r\n\r\n  import Toolbar from \"./Components/App/Toolbar.svelte\";\r\n</script>\r\n\r\n<Router>\r\n  <div class=\"app--main\">\r\n    <Toolbar />\r\n    <div class=\"content-container\">\r\n      <Menu />\r\n      <div class=\"panel\">\r\n        <Route path=\"/editor\">\r\n          <EditorPage />\r\n        </Route>\r\n        <Route path=\"/editor/:namespace\" let:params>\r\n          <EditorPage namespace={params.namespace} />\r\n        </Route>\r\n        <Route path=\"/about\" component={About} />\r\n        <Route path=\"/\">\r\n          <Home />\r\n        </Route>\r\n        <Route path=\"/home\">\r\n          <Home />\r\n        </Route>\r\n      </div